use anyhow::Result;
use ml_dsa::signature::Verifier;
use ml_dsa::{EncodedSignature, EncodedVerifyingKey, MlDsa44, Signature, VerifyingKey};

use crate::transport::CardTransport;

const CLA: u8 = 0x00;
const INS_GET_PUBKEY: u8 = 0x30;
const INS_GET_RESPONSE: u8 = 0xC0;

pub fn get_pubkey(transport: &mut CardTransport) -> Result<Vec<u8>> {
    let apdu = vec![CLA, INS_GET_PUBKEY, 0x00, 0x00, 0x00];
    let first = transport.send_apdu(&apdu)?;
    transport.collect_chunked(first, INS_GET_RESPONSE)
}

pub fn verify_signature(pubkey: &[u8], digest: &[u8; 32], sig: &[u8]) -> Result<bool> {
    let enc_vk = EncodedVerifyingKey::<MlDsa44>::try_from(pubkey)?;
    let vk = VerifyingKey::<MlDsa44>::decode(&enc_vk);

    let enc_sig = EncodedSignature::<MlDsa44>::try_from(sig)?;
    let signature = Signature::<MlDsa44>::decode(&enc_sig)
        .ok_or_else(|| anyhow::anyhow!("Invalid signature"))?;

    Ok(vk.verify(digest, &signature).is_ok())
}

#[cfg(test)]
mod tests {
    use super::*;

    const PUBKEY_HEX: &str = "";
    const SIG_HEX: &str = "";
    const DIGEST_HEX: &str = "3a985da74fe225b2045c172d6bd390bd855f086e3e9d525b46bfe24511431532";

    #[test]
    fn card_signature_verifies() {
        let pubkey = hex::decode(PUBKEY_HEX).unwrap();
        let sig = hex::decode(SIG_HEX).unwrap();
        let digest_vec = hex::decode(DIGEST_HEX).unwrap();
        let digest: [u8; 32] = digest_vec.try_into().unwrap();

        assert!(verify_signature(&pubkey, &digest, &sig).unwrap());
    }
}
